local FarmLeft  = Tabs.Farm:AddLeftGroupbox("Configuração do Farm ")
local FarmRight = Tabs.Farm:AddRightGroupbox("Status ")

local statusLabel = FarmRight:AddLabel({ Text = "Status: Inativo " })
local worldLabel  = FarmRight:AddLabel({ Text = "Torre: detectando... " })

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        if M.isSharedStallActive() then
            local remaining = math.max(0, math.ceil(M.getSharedStallUntil() - tick()))
            statusLabel:SetText("Status: Stalled " .. remaining .. "s ")
        elseif M.isClaimingWins() then
            statusLabel:SetText("Status: Coletando Vitórias ")
        elseif M.isListening() then
            statusLabel:SetText("Status: Aguardando... ")
        elseif M.isAllCaptured() then
            statusLabel:SetText("Status: Pronto! ")
        else
            statusLabel:SetText("Status: Ainda não configurado ")
        end
        worldLabel:SetText("Tower: " .. (M.getCurrentWorldName() or "not found") .. " ")
    end
end)

FarmLeft:AddToggle("AutoSetupToggle", {
