-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Substituição de Posição ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Tecla de Salvamento Rápido ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Posição Personalizada: DESLIGADA " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Salvo: nenhum " })

SpotLeft:AddButton("Salvar Posição Atual ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Erro ", Description="Sem personagem! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Erro ", Description="Sem HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="Posição Salva! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("Limpar Posição Personalizada ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Salvo: nenhum ")
    Library:Notify({Title="Limpo ", Description="Usando o local original capturado. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

local keybindLabel = SpotRight:AddLabel({ Text = "Tecla de Salvamento Rápido: F" })

SpotRight:AddButton("Definir Tecla de Salvamento Rápido ", function()
    M.setSettingKeybind(true)
    keybindLabel:SetText("Pressione uma tecla agora... ")
    Library:Notify({Title="Pressione Qualquer Tecla ", Description="Essa tecla salvará seu local. ", Duration=4})
end)

SpotRight:AddButton("Limpar Tecla de Salvamento Rápido ", function()
    M.setTeleportKeybind(nil)
    keybindLabel:SetText("Tecla de Salvamento Rápido: nenhuma ")
    Library:Notify({Title="Tecla Limpa ", Description="Nenhuma tecla de salvamento rápido definida. ", Duration=3})
end)

M.onKeybindSet = function(keyCode)
    keybindLabel:SetText("Quick-Save Key: " .. keyCode.Name .. " ")
end

M.onSpotSaved = function(p)
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
end

